customCss:
@import url('https://fonts.googleapis.com/css2?family=Righteous&family=Quicksand:wght@400;500;600;700&display=swap');
:root { --font-body: 'Quicksand', sans-serif; --font-display: 'Righteous', cursive; --radius: 18px; --ambient-glow-opacity: 0.22; --hero-backdrop-brightness: 0.6; --hero-backdrop-saturate: 1.8; }

/* ═══════════════════════════════════════
   SIDEBAR — Floating glass overlay
   ═══════════════════════════════════════ */
aside { margin: 14px !important; border-radius: 22px !important; border: 1px solid rgba(255,113,206,0.15) !important; height: calc(100dvh - 28px) !important; background: rgba(12,6,24,0.75) !important; backdrop-filter: blur(24px) saturate(1.5) !important; -webkit-backdrop-filter: blur(24px) saturate(1.5) !important; box-shadow: 0 8px 40px rgba(0,0,0,0.4), 0 0 0 1px rgba(185,103,255,0.08); overflow: hidden; }
aside::before { content: ''; position: absolute; inset: 0; border-radius: 22px; background: linear-gradient(180deg, rgba(255,113,206,0.04) 0%, transparent 30%, transparent 70%, rgba(1,205,254,0.04) 100%); pointer-events: none; }

.sidebar-logo-icon { border-radius: 14px !important; background: linear-gradient(135deg, rgba(255,113,206,0.25), rgba(1,205,254,0.25)) !important; border: 1px solid rgba(255,113,206,0.3) !important; box-shadow: 0 4px 12px rgba(255,113,206,0.15); }
.sidebar-logo-text { font-family: 'Righteous', cursive !important; letter-spacing: 0.06em !important; font-size: 1rem !important; }

/* Nav items: soft rounded pills */
.sidebar-nav-item { border-radius: 14px !important; font-weight: 600; }
.sidebar-footer { border-top: 1px solid rgba(185,103,255,0.1) !important; }

/* ═══════════════════════════════════════
   HERO — Contained card, not full-bleed
   ═══════════════════════════════════════ */
.home-hero { margin: 0 16px !important; border-radius: 24px !important; border: 1px solid rgba(185,103,255,0.12) !important; overflow: hidden !important; min-height: 65dvh !important; box-shadow: 0 12px 50px rgba(0,0,0,0.5), 0 0 0 1px rgba(255,113,206,0.06); }
@media (min-width: 1024px) { .home-hero { margin: 0 24px !important; min-height: 72dvh !important; } }

/* Retro grid floor in hero */
.home-hero::after { content: ''; position: absolute; bottom: 0; left: 0; right: 0; height: 45%; background: linear-gradient(transparent 0%, rgba(255,113,206,0.04) 100%), repeating-linear-gradient(90deg, rgba(1,205,254,0.05) 0px, transparent 1px, transparent 50px), repeating-linear-gradient(0deg, rgba(1,205,254,0.05) 0px, transparent 1px, transparent 50px); pointer-events: none; z-index: 4; mask-image: linear-gradient(transparent, black); -webkit-mask-image: linear-gradient(transparent, black); }

/* Hero title: display font */
.home-hero h1 { font-family: 'Righteous', cursive !important; }

/* Detail hero: contained */
.item-detail-hero { margin: 0 16px !important; border-radius: 24px !important; border: 1px solid rgba(185,103,255,0.1) !important; overflow: hidden !important; box-shadow: 0 12px 40px rgba(0,0,0,0.4); }
@media (min-width: 1024px) { .item-detail-hero { margin: 0 24px !important; } }

/* ═══════════════════════════════════════
   CARDS — Extra round, glow, wider
   ═══════════════════════════════════════ */
.media-card-image { border-radius: 16px !important; border: 1px solid rgba(255,113,206,0.15) !important; box-shadow: 0 4px 16px rgba(0,0,0,0.3); transition: all 0.4s cubic-bezier(0.34, 1.56, 0.64, 1) !important; overflow: hidden; }
.media-card:hover .media-card-image { box-shadow: 0 8px 32px rgba(255,113,206,0.25), 0 4px 16px rgba(1,205,254,0.12) !important; border-color: rgba(255,113,206,0.4) !important; }
.media-card:hover { transform: translateY(-8px) scale(1.03) !important; }

/* ═══════════════════════════════════════
   SECTION ROWS — Gradient text headers
   ═══════════════════════════════════════ */
.section-row h2 { font-family: 'Righteous', cursive !important; font-size: 1.15rem !important; letter-spacing: 0.04em; background: linear-gradient(135deg, #ff71ce, #01cdfe) !important; -webkit-background-clip: text !important; -webkit-text-fill-color: transparent !important; background-clip: text !important; }
.section-row h2 span { -webkit-text-fill-color: transparent; background: linear-gradient(135deg, #ff71ce80, #01cdfe80); -webkit-background-clip: text; background-clip: text; }

/* ═══════════════════════════════════════
   DETAIL PAGE — Spacious, dreamy
   ═══════════════════════════════════════ */
.page-title { font-family: 'Righteous', cursive !important; }
.page-shell h2 { font-family: 'Righteous', cursive; font-size: 1.1rem; }

/* ═══════════════════════════════════════
   BADGES, BUTTONS & UI
   ═══════════════════════════════════════ */
.metadata-badge { border-radius: 9999px !important; background: linear-gradient(135deg, rgba(255,113,206,0.1), rgba(1,205,254,0.1)) !important; border: 1px solid rgba(255,113,206,0.2) !important; }
.pill { border-radius: 9999px !important; }
.pill-primary { background: linear-gradient(135deg, #ff71ce, #b967ff) !important; border: none !important; box-shadow: 0 4px 18px rgba(255,113,206,0.3), 0 0 0 1px rgba(255,113,206,0.1); }
.pill-primary:hover { box-shadow: 0 8px 28px rgba(255,113,206,0.5), 0 0 0 1px rgba(255,113,206,0.2) !important; transform: translateY(-2px); }
.pill-glass { border-radius: 9999px !important; border: 1px solid rgba(185,103,255,0.2) !important; }
.action-circle { background: linear-gradient(135deg, rgba(255,113,206,0.1), rgba(1,205,254,0.1)) !important; border: 1px solid rgba(185,103,255,0.15); }

/* Tab bar: pill style */
.tab-active { border-radius: 9999px !important; background: linear-gradient(135deg, rgba(255,113,206,0.15), rgba(1,205,254,0.15)) !important; border: 1px solid rgba(255,113,206,0.15); }

/* ═══════════════════════════════════════
   GLASS & SURFACES — Extra frosted, round
   ═══════════════════════════════════════ */
.glass, .glass-subtle { border-radius: 18px !important; border: 1px solid rgba(185,103,255,0.12) !important; backdrop-filter: blur(20px) saturate(1.3) !important; }
.glass-dark { border-radius: 18px !important; border: 1px solid rgba(185,103,255,0.1) !important; }
.surface-panel { border-radius: 20px !important; border: 1px solid rgba(185,103,255,0.08) !important; box-shadow: 0 4px 20px rgba(0,0,0,0.25); }

/* ═══════════════════════════════════════
   MOBILE HEADER — Rounded glass
   ═══════════════════════════════════════ */
.mobile-header { border-radius: 20px !important; border: 1px solid rgba(255,113,206,0.15) !important; box-shadow: 0 4px 20px rgba(0,0,0,0.3); }

/* ═══════════════════════════════════════
   PROGRESS & MISC
   ═══════════════════════════════════════ */
.progress-fill { background: linear-gradient(90deg, #ff71ce, #01cdfe) !important; border-radius: 9999px !important; }
.dot { border-radius: 9999px !important; }
.dot-active { border-radius: 9999px !important; }

/* Carousel arrows: round glass */
.home-hero button[class*='glass-subtle'] { border-radius: 9999px !important; border: 1px solid rgba(255,113,206,0.2) !important; }

/* Inputs: extra round */
input, textarea, select { border-radius: 14px !important; }

/* Background pattern: subtle grid */
body::before { content: ''; position: fixed; inset: 0; background: repeating-linear-gradient(90deg, rgba(185,103,255,0.015) 0px, transparent 1px, transparent 80px), repeating-linear-gradient(0deg, rgba(185,103,255,0.015) 0px, transparent 1px, transparent 80px); pointer-events: none; z-index: 0; }
